  input clk, en ;
  input  [n-1:0] in ;
  output [n-1:0] out ;
  reg    [n-1:0] out ;
  wire   [n-1:0] next_out ;

  wire __cond2_tmp = en;
  assign next_out = __cond2_tmp ? in : out;

  always @(posedge clk)
